import React, { useState, useEffect, useRef } from 'react';
import { getHero, uploadHeroImage, deleteHeroImage } from '../services/api';
import { useAuth } from '../context/AuthContext';
import Toast from '../components/Toast';

export default function ManageHeroPage() {
  const { token } = useAuth();
  const [images, setImages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const fileRef = useRef(null);

  const load = async () => {
    try {
      setLoading(true); setError('');
      const res = await getHero();
      if (res.success) setImages(res.data.images || []);
      else setError(res.message || 'Failed to load');
    } catch (err) { setError(err.message || 'Failed to load'); }
    finally { setLoading(false); }
  };

  useEffect(() => { load(); }, []);

  const handleUpload = async (e) => {
    const f = e.target.files?.[0];
    if (!f) return;
    const fd = new FormData();
    fd.append('image', f);
    try {
      setLoading(true); setError(''); setSuccess('');
      const res = await uploadHeroImage(token, fd);
      if (res.success) {
        setImages(res.data.images || []);
        setSuccess('Image uploaded');
        fileRef.current.value = '';
      } else setError(res.message || 'Upload failed');
    } catch (err) { setError(err.message || 'Upload failed'); }
    finally { setLoading(false); }
  };

  const handleDelete = async (publicId) => {
    if (!window.confirm('Delete this hero image?')) return;
    try {
      setLoading(true); setError(''); setSuccess('');
      const res = await deleteHeroImage(token, publicId);
      if (res.success) {
        setImages(prev => prev.filter(i => i.publicId !== publicId));
        setSuccess('Deleted');
      } else setError(res.message || 'Delete failed');
    } catch (err) { setError(err.message || 'Delete failed'); }
    finally { setLoading(false); }
  };

  return (
    <div className="manage-page">
      <h2 style={{ marginBottom: 12 }}>Hero Images</h2>
      <Toast message={error} type="error" onClose={() => setError('')} />
      <Toast message={success} type="success" onClose={() => setSuccess('')} />

      <div style={{ marginBottom: 16 }}>
        <input ref={fileRef} type="file" accept="image/*" onChange={handleUpload} />
      </div>

      {loading ? <div>Loading...</div> : (
        <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
          {images.length ? images.map(img => (
            <div key={img.publicId} style={{ width: 220, border: '1px solid #eee', borderRadius: 8, padding: 8 }}>
              <img src={img.url} alt={img.fileName || ''} style={{ width: '100%', height: 120, objectFit: 'cover', borderRadius: 6 }} />
              <div style={{ marginTop: 8, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div style={{ fontSize: 12, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{img.fileName}</div>
                <button type="button" className="btn-danger" onClick={() => handleDelete(img.publicId)}>Delete</button>
              </div>
            </div>
          )) : <div>No hero images configured.</div>}
        </div>
      )}
    </div>
  );
}
